import psycopg2
from psycopg2 import Error


def search_users(username=None, email=None, role=None, status=None):
    """
    Search users by username, email, role and status.
    :param username: str
    :param email: str
    :param role: str
    :param status: str
    :return: list of dicts
    """

    try:
        conn = psycopg2.connect(
            host='localhost',
            database='postgres',
            user='postgres',
            password='<PASSWORD>'
        )

        cursor = conn.cursor()

        query_params = []
        query = 'SELECT * FROM users WHERE 1=1'

        if username is not None:
            query += " AND username LIKE %s"
            query_params.append(f'%{username}%')

        if email is not None:
            query += " AND email LIKE %s"
            query_params.append(f'%{email}%')

        if role is not None:
            query += " AND role = %s"
            query_params.append(role)

        if status is not None:
            query += " AND status = %s"
            query_params.append(status)

        cursor.execute(query, tuple(query_params))
        return [dict(zip([desc[0] for desc in cursor.description], row))
                for row in cursor.fetchall()]

    except (Exception, Error) as error:
        print("Error while connecting to PostgreSQL", error)
    finally:
        # closing database connection.
        if conn is not None:
            conn.close()


if __name__ == '__main__':
    print(search_users())
    print(search_users(username='john'))
    print(search_users(email='<EMAIL>'))
    print(search_users(role='admin'))
    print(search_users(status='active'))
    print(search_users(username='john', role='admin'))